function getTxtNumbers(typed){
	$.ajax({
		url: "/ajax_search_auto.php?mdl=txtdelay&q=" + typed, 
		cache : false,
		success: function(result){ 
			if(parseInt(result) > 0){
				$('.txtcount').children('img').remove();
				$('.txtcount').html(result);
				$('.txtcount').parent().parent().removeClass('n0').addClass('n' + result.trim());
				$('.txtcount').removeClass('txtcount');			
			}
			else{
				$('.txtcount').children('img').remove();
				$('.txtcount').html(result);
				$('.txtcount').removeClass('txtcount');	
			}			
		}
	});
}

