    let notification = $('textarea[name=bildirim-bildirim]');
    let name = $('input[name=bildirim-ad-soyad]');
    let email = $('input[name=bildirim-eposta]');
    let phone = $('input[name=bildirim-telefon]');
    let code = $('input[name=bildirim-kodu]');
    let submitBtn = $('#modal-issue-submit');
    let loader = $('.modal-loading');

if (lock) {
        notification.prop('disabled', true);
        name.prop('disabled', true);
        email.prop('disabled', true);
        phone.prop('disabled', true);
        code.prop('disabled', true);
        submitBtn.hide();
        loader.show();
    } else {
        notification.prop('disabled', false);
        name.prop('disabled', false);
        email.prop('disabled', false);
        phone.prop('disabled', false);
        code.prop('disabled', false);
        submitBtn.show();
        loader.hide();
    }
}

function resizeFotorama(fotorama) {
    let activeFrame = fotorama.activeFrame.$stageFrame;
    let activeImage = activeFrame.find('img.fotorama__img');
    let activeCaption = activeFrame.find('div.fotorama__caption');
    let hesap = activeFrame.height() - activeCaption.height();
    let cssTag = $('#fotorama_max');
    if (cssTag.length > 0)
        cssTag.remove()
    activeImage.parent().append('<style id="fotorama_max">.fotorama_max { max-height: '+ hesap +'px !important; }</style>')
    activeImage.addClass('fotorama_max');
}

