issueModal.on('change', function () {
        let form = $('#modal-issue-form');
        let bildirimText = form.find('textarea[name="bildirim-bildirim"]');
        if (issue && bildirimText.val().length > 0) {
            let excludes = ['g-token'];
            let cookie = 'bildirim_' + issue;
            let formData = form.serializeArray();
            $.each(formData, function (index, item) {
                if (item && excludes.indexOf(item.name) > -1)
                    formData.splice(index, 1);
            });
            localStorage.setItem(cookie, JSON.stringify(formData));
        }
    });

