function getType(times)
{
    delay(function(){
		var typed = $.trim($('#searchBox').val());
		if(typed.length > 1)
		{
				autocomplete(typed );
		}
		else
		{
			$("#auto-suggest-box").hide();	
			$("#auto-suggest-loading").hide();

		}
    }, times );
}

