		function addCurrentLetter(letter)
		{
			var selStart = $("#searchBox")[0].selectionStart;
			var selEnd = $("#searchBox")[0].selectionEnd;
			var character = letter; 
			var textAreaStr = $('#searchBox').val();
			var value = textAreaStr.substring(0, selStart) + character + textAreaStr.substring(selEnd);
			$("#searchBox").val(value).focus();
			$("#searchBox")[0].selectionStart = selStart+1, $("#searchBox")[0].selectionEnd = selStart+1;				
		}

function deleteCurrentLetter()
		{
			var selStart = $("#searchBox")[0].selectionStart;
			var selEnd = $("#searchBox")[0].selectionEnd;
			var textAreaStr = $('#searchBox').val();
			var value = textAreaStr.substring(0, selStart-1) + textAreaStr.substring(selEnd);
			$("#searchBox").val(value).focus();
			$("#searchBox")[0].selectionStart = selStart-1, $("#searchBox")[0].selectionEnd = selStart-1;				
		}		

		$('.shift').click(function(event){

			$('.dia-keyboard ul li').each(function(){
				if(isCapital){
					$(this).text($(this).attr("hk"));
				}
				else{
					$(this).text($(this).attr("hb"));
				}
			});

			if(isCapital){
				isCapital = false;
			}else{
				isCapital = true;
			}
		});

		$('.dia-keyboard ul li:not(.noletter)').click(function(event){
