$("#searchBox").keydown(function(e) {

  var searchbox = $(this);
  switch (e.which) {
    case 40:
      e.preventDefault(); // prevent moving the cursor     
	  if($('#searc-complete-result .alist a.selected').length == 0){
		$('#searc-complete-result .alist a:first').addClass('selected');
	  }else{
		$('#searc-complete-result .alist a:not(:last-child).selected').removeClass('selected').next().addClass('selected');
	  }
      break;
    case 38:
      e.preventDefault(); // prevent moving the cursor
	  if($('#searc-complete-result a:first.selected').length == 1){
		$('#searc-complete-result .selected').removeClass('selected');
	  }
      $('#searc-complete-result a:not(:first-child).selected').removeClass('selected').prev().addClass('selected');
      break;
  }
});

