		clearTimeout (timer);
		timer = setTimeout(callback, ms);
	  };
	})();
	$('#searchBox1').keyup(function() {
		delay(function(){
		var typed = $.trim($('#searchBox1').val());
		if(typed.length > 1)
		{
				autocomplete(typed );
		}
		else
		{
			$("#auto-suggest-box1").hide();
			$("#auto-suggest-loading1").hide();

		}
		}, 1000 );
	});

	function autocomplete(typed)
	{
		$("#auto-suggest-content1").html('');
		$("#auto-suggest-box1").show();
		$("#auto-suggest-loading1").show();

		$.ajax({
			url: "/ajax_search_auto.php?q=" + typed,
			cache : false,
			success: function(result){
				if(result.trim() == "")
				{
					$("#auto-suggest-box1").hide();
					$("#auto-suggest-loading1").hide();
				}else{
					$("#auto-suggest-loading1").hide();
					$("#auto-suggest-content1").html(result);
				}
			}
		});
	}

/* atif */
	$('.atif-btn').click(function(){
		$(this).parent().parent().parent().parent().find('.atif-kutusu').slideToggle();
	});

	$(document).mouseup(function (e)
	{
		var resultbox = $(".atif-kutusu");
